"""Embedded PitchCoach frontend (generated from index.html).
Regenerate by editing HTML and re-embedding via repr().
"""

HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>PitchCoach</title>\n  <style>\n    :root {\n      --bg: #0f1117;\n      --surface: #1e2130;\n      --surface2: #262a3a;\n      --border: #2e3248;\n      --accent: #7c6af7;\n      --accent-dim: #4f46a8;\n      --good: #22c55e;\n      --bad: #ef4444;\n      --text: #e8eaf0;\n      --text-dim: #8892a4;\n      --radius: 12px;\n    }\n\n    * { box-sizing: border-box; margin: 0; padding: 0; }\n\n    body {\n      background: var(--bg);\n      color: var(--text);\n      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;\n      min-height: 100vh;\n      display: flex;\n      flex-direction: column;\n      align-items: center;\n      padding: 2rem 1rem;\n    }\n\n    header {\n      text-align: center;\n      margin-bottom: 2.5rem;\n    }\n    header h1 { font-size: 2.2rem; font-weight: 700; letter-spacing: -0.5px; }\n    header h1 span { color: var(--accent); }\n    header p  { color: var(--text-dim); margin-top: 0.5rem; font-size: 1rem; max-width: 500px; }\n\n    .card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: var(--radius);\n      padding: 1.5rem;\n      width: 100%;\n      max-width: 680px;\n      margin-bottom: 1.25rem;\n    }\n\n    .card h2 {\n      font-size: 0.8rem;\n      text-transform: uppercase;\n      letter-spacing: 1px;\n      color: var(--text-dim);\n      margin-bottom: 1rem;\n    }\n\n    /* ── upload zone ─────────────────────────────────────────────── */\n    .drop-zone {\n      border: 2px dashed var(--border);\n      border-radius: var(--radius);\n      padding: 2.5rem 1rem;\n      text-align: center;\n      cursor: pointer;\n      transition: border-color 0.2s, background 0.2s;\n    }\n    .drop-zone:hover, .drop-zone.dragover {\n      border-color: var(--accent);\n      background: rgba(124, 106, 247, 0.05);\n    }\n    .drop-zone .icon { font-size: 2.5rem; display: block; margin-bottom: 0.75rem; }\n    .drop-zone p { color: var(--text-dim); font-size: 0.9rem; }\n    .drop-zone p strong { color: var(--text); }\n    #file-input { display: none; }\n\n    .file-info {\n      display: none;\n      margin-top: 1rem;\n      padding: 0.75rem 1rem;\n      background: var(--surface2);\n      border-radius: 8px;\n      font-size: 0.875rem;\n      align-items: center;\n      gap: 0.75rem;\n    }\n    .file-info.show { display: flex; }\n    .file-info .fname { font-weight: 500; flex: 1; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }\n    .file-info .fsize { color: var(--text-dim); white-space: nowrap; }\n\n    audio { width: 100%; margin-top: 1rem; border-radius: 8px; display: none; }\n    audio.show { display: block; }\n\n    /* ── button ──────────────────────────────────────────────────── */\n    button.primary {\n      width: 100%;\n      max-width: 680px;\n      padding: 0.85rem;\n      background: var(--accent);\n      color: #fff;\n      border: none;\n      border-radius: var(--radius);\n      font-size: 1rem;\n      font-weight: 600;\n      cursor: pointer;\n      transition: background 0.2s, opacity 0.2s;\n      margin-bottom: 1.25rem;\n    }\n    button.primary:hover:not(:disabled) { background: var(--accent-dim); }\n    button.primary:disabled { opacity: 0.45; cursor: not-allowed; }\n\n    /* ── spinner ─────────────────────────────────────────────────── */\n    .spinner {\n      display: none;\n      align-items: center;\n      gap: 0.75rem;\n      color: var(--text-dim);\n      font-size: 0.9rem;\n      justify-content: center;\n      margin-bottom: 1.25rem;\n    }\n    .spinner.show { display: flex; }\n    .spinner-ring {\n      width: 20px; height: 20px;\n      border: 2px solid var(--border);\n      border-top-color: var(--accent);\n      border-radius: 50%;\n      animation: spin 0.7s linear infinite;\n    }\n    @keyframes spin { to { transform: rotate(360deg); } }\n\n    /* ── error banner ────────────────────────────────────────────── */\n    .error-banner {\n      display: none;\n      width: 100%; max-width: 680px;\n      background: rgba(239, 68, 68, 0.12);\n      border: 1px solid var(--bad);\n      border-radius: var(--radius);\n      padding: 0.85rem 1rem;\n      color: var(--bad);\n      font-size: 0.9rem;\n      margin-bottom: 1.25rem;\n    }\n    .error-banner.show { display: block; }\n\n    /* ── results ─────────────────────────────────────────────────── */\n    #results { display: none; width: 100%; max-width: 680px; }\n    #results.show { display: block; }\n\n    .transcript-text {\n      background: var(--surface2);\n      border-radius: 8px;\n      padding: 1rem;\n      font-size: 0.9rem;\n      line-height: 1.6;\n      color: var(--text);\n      max-height: 200px;\n      overflow-y: auto;\n    }\n    .word-count { color: var(--text-dim); font-size: 0.8rem; margin-top: 0.5rem; }\n\n    .verdict {\n      display: flex;\n      align-items: center;\n      gap: 1rem;\n      flex-wrap: wrap;\n    }\n    .badge {\n      display: inline-flex;\n      align-items: center;\n      gap: 0.4rem;\n      font-weight: 700;\n      font-size: 1rem;\n      padding: 0.5rem 1rem;\n      border-radius: 99px;\n    }\n    .badge.good { background: rgba(34, 197, 94, 0.15); color: var(--good); }\n    .badge.bad  { background: rgba(239, 68, 68, 0.15); color: var(--bad); }\n\n    .metrics { display: flex; gap: 1rem; flex-wrap: wrap; margin-top: 0.75rem; }\n    .metric { flex: 1; min-width: 130px; }\n    .metric .label { font-size: 0.75rem; color: var(--text-dim); margin-bottom: 0.3rem; }\n    .metric .value { font-size: 1.5rem; font-weight: 700; }\n    .metric .value.good { color: var(--good); }\n    .metric .value.bad  { color: var(--bad); }\n\n    .progress-bar-wrap {\n      background: var(--surface2);\n      border-radius: 99px;\n      height: 10px;\n      margin-top: 1rem;\n      overflow: hidden;\n    }\n    .progress-bar {\n      height: 100%;\n      border-radius: 99px;\n      background: linear-gradient(90deg, var(--accent-dim), var(--accent));\n      transition: width 0.6s ease;\n    }\n    .progress-label {\n      display: flex;\n      justify-content: space-between;\n      font-size: 0.75rem;\n      color: var(--text-dim);\n      margin-top: 0.35rem;\n    }\n\n    .interpretation {\n      font-size: 0.9rem;\n      line-height: 1.7;\n      color: var(--text-dim);\n    }\n    .interpretation strong { color: var(--text); }\n    .interpretation ul { margin-top: 0.5rem; padding-left: 1.2rem; }\n    .interpretation li { margin-bottom: 0.35rem; }\n\n    .feedback-text {\n      font-size: 0.9rem;\n      line-height: 1.75;\n      color: var(--text-dim);\n      white-space: pre-wrap;\n    }\n    .feedback-text strong { color: var(--text); }\n\n    footer {\n      margin-top: 3rem;\n      color: var(--text-dim);\n      font-size: 0.78rem;\n      text-align: center;\n    }\n  </style>\n</head>\n<body>\n\n<header>\n  <h1>🎙️ Pitch<span>Coach</span></h1>\n  <p>Upload a business pitch recording and get instant AI feedback powered by Whisper + BERT + Gemini.</p>\n</header>\n\n<!-- upload card -->\n<div class="card">\n  <h2>Your pitch recording</h2>\n  <div class="drop-zone" id="drop-zone" onclick="document.getElementById(\'file-input\').click()">\n    <span class="icon">🎤</span>\n    <p><strong>Click to upload</strong> or drag &amp; drop</p>\n    <p style="margin-top:0.3rem">WAV · MP3 · M4A · OGG · FLAC · WebM &nbsp;·&nbsp; Max ~4 MB</p>\n  </div>\n  <input type="file" id="file-input" accept=".wav,.mp3,.m4a,.ogg,.flac,.webm,audio/*" />\n  <div class="file-info" id="file-info">\n    <span>📄</span>\n    <span class="fname" id="file-name"></span>\n    <span class="fsize" id="file-size"></span>\n  </div>\n  <audio id="audio-player" controls></audio>\n</div>\n\n<button class="primary" id="analyze-btn" disabled>Analyze my pitch</button>\n\n<div class="spinner" id="spinner">\n  <div class="spinner-ring"></div>\n  <span id="spinner-msg">Uploading…</span>\n</div>\n\n<div class="error-banner" id="error-banner"></div>\n\n<!-- results -->\n<div id="results">\n  <div class="card">\n    <h2>Transcript</h2>\n    <div class="transcript-text" id="transcript"></div>\n    <p class="word-count" id="word-count"></p>\n  </div>\n\n  <div class="card">\n    <h2>Pitch quality</h2>\n    <div class="verdict">\n      <div class="badge" id="verdict-badge"></div>\n    </div>\n    <div class="metrics">\n      <div class="metric">\n        <div class="label">Good pitch score</div>\n        <div class="value good" id="good-pct"></div>\n      </div>\n      <div class="metric">\n        <div class="label">Needs-work score</div>\n        <div class="value bad" id="bad-pct"></div>\n      </div>\n    </div>\n    <div class="progress-bar-wrap">\n      <div class="progress-bar" id="progress-bar" style="width:0%"></div>\n    </div>\n    <div class="progress-label">\n      <span>Bad</span><span>Good</span>\n    </div>\n  </div>\n\n  <div class="card" id="interpretation-card">\n    <h2>What this means</h2>\n    <div class="interpretation" id="interpretation"></div>\n  </div>\n\n  <div class="card" id="feedback-card" style="display:none">\n    <h2>Gemini\'s coaching feedback</h2>\n    <div class="feedback-text" id="feedback"></div>\n  </div>\n</div>\n\n<footer>PitchCoach &nbsp;·&nbsp; DistilBERT fine-tuned on 83 entrepreneur pitches &nbsp;·&nbsp; Transcription by Groq Whisper Large V3 &nbsp;·&nbsp; Coaching by Gemini</footer>\n\n<script>\n  const dropZone   = document.getElementById("drop-zone");\n  const fileInput  = document.getElementById("file-input");\n  const fileInfo   = document.getElementById("file-info");\n  const fileName   = document.getElementById("file-name");\n  const fileSize   = document.getElementById("file-size");\n  const audioEl    = document.getElementById("audio-player");\n  const analyzeBtn = document.getElementById("analyze-btn");\n  const spinner    = document.getElementById("spinner");\n  const spinnerMsg = document.getElementById("spinner-msg");\n  const errorBanner= document.getElementById("error-banner");\n  const results    = document.getElementById("results");\n\n  let selectedFile = null;\n\n  function formatBytes(bytes) {\n    if (bytes < 1024) return bytes + " B";\n    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";\n    return (bytes / (1024 * 1024)).toFixed(1) + " MB";\n  }\n\n  function setFile(file) {\n    if (!file) return;\n    selectedFile = file;\n    fileName.textContent = file.name;\n    fileSize.textContent = formatBytes(file.size);\n    fileInfo.classList.add("show");\n    audioEl.src = URL.createObjectURL(file);\n    audioEl.classList.add("show");\n    analyzeBtn.disabled = false;\n    errorBanner.classList.remove("show");\n    results.classList.remove("show");\n  }\n\n  fileInput.addEventListener("change", () => setFile(fileInput.files[0]));\n\n  dropZone.addEventListener("dragover", (e) => { e.preventDefault(); dropZone.classList.add("dragover"); });\n  dropZone.addEventListener("dragleave", () => dropZone.classList.remove("dragover"));\n  dropZone.addEventListener("drop", (e) => {\n    e.preventDefault();\n    dropZone.classList.remove("dragover");\n    setFile(e.dataTransfer.files[0]);\n  });\n\n  function showError(msg) {\n    errorBanner.textContent = "⚠ " + msg;\n    errorBanner.classList.add("show");\n    spinner.classList.remove("show");\n    analyzeBtn.disabled = false;\n  }\n\n  function renderMarkdown(text) {\n    // minimal markdown: **bold**, bullet lists, newlines\n    return text\n      .replace(/\\*\\*(.*?)\\*\\*/g, "<strong>$1</strong>")\n      .replace(/^- (.+)$/gm, "<li>$1</li>")\n      .replace(/(<li>.*<\\/li>)/s, "<ul>$1</ul>")\n      .replace(/\\n/g, "<br>");\n  }\n\n  analyzeBtn.addEventListener("click", async () => {\n    if (!selectedFile) return;\n\n    const MAX_BYTES = 4.4 * 1024 * 1024;  // Vercel serverless body limit ~4.5 MB\n    if (selectedFile.size > MAX_BYTES) {\n      showError("Audio is " + formatBytes(selectedFile.size) + " — the server accepts up to ~4.4 MB. Upload a shorter or more compressed clip (MP3/M4A work best).");\n      return;\n    }\n\n    analyzeBtn.disabled = true;\n    errorBanner.classList.remove("show");\n    results.classList.remove("show");\n    spinner.classList.add("show");\n    spinnerMsg.textContent = "Transcribing with Whisper…";\n\n    const formData = new FormData();\n    formData.append("audio", selectedFile, selectedFile.name);\n\n    try {\n      spinnerMsg.textContent = "Classifying with BERT…";\n      const resp = await fetch("/api/analyze", { method: "POST", body: formData });\n      const raw = await resp.text();\n      let data;\n      try { data = JSON.parse(raw); }\n      catch (e) {\n        analyzeBtn.disabled = false;\n        spinner.classList.remove("show");\n        showError(resp.status === 413\n          ? "Audio too large for the server (Vercel ~4.5 MB limit). Use a shorter or compressed clip."\n          : ("Server error " + resp.status + ": " + raw.slice(0, 180)));\n        return;\n      }\n\n      if (!resp.ok) {\n        showError(data.detail || `Server error (${resp.status})`);\n        return;\n      }\n\n      spinner.classList.remove("show");\n      analyzeBtn.disabled = false;\n\n      // transcript\n      document.getElementById("transcript").textContent = data.transcript;\n      document.getElementById("word-count").textContent = `${data.word_count} words transcribed`;\n\n      // classification\n      const cls   = data.classification;\n      const label = cls.label;\n      const goodPct = Math.round(cls.good_prob * 100);\n      const badPct  = Math.round(cls.bad_prob  * 100);\n\n      const badge = document.getElementById("verdict-badge");\n      badge.textContent = label === "good" ? "✅ Good pitch" : "❌ Needs work";\n      badge.className = "badge " + label;\n\n      document.getElementById("good-pct").textContent = goodPct + "%";\n      document.getElementById("bad-pct").textContent  = badPct  + "%";\n      document.getElementById("progress-bar").style.width = goodPct + "%";\n\n      // interpretation\n      const interp = document.getElementById("interpretation");\n      if (label === "good") {\n        interp.innerHTML = `Your pitch scored <strong>${goodPct}% good</strong> — it shares characteristics with influential speeches in our training set.<br><br>\n          <strong>Common traits of good pitches:</strong>\n          <ul>\n            <li>Clear problem + solution framing</li>\n            <li>Confident, direct language with minimal hedging</li>\n            <li>Concrete specifics — numbers, names, timelines</li>\n            <li>A compelling call to action</li>\n          </ul>`;\n      } else {\n        interp.innerHTML = `Your pitch scored <strong>${badPct}% needs work</strong> — it shares traits with weaker pitches in our training set.<br><br>\n          <strong>Common weaknesses to address:</strong>\n          <ul>\n            <li>Vague language or excessive jargon</li>\n            <li>Lack of structure: problem → solution → traction → ask</li>\n            <li>Too many filler words or hedges ("sort of", "I think maybe")</li>\n            <li>Missing a clear call to action</li>\n          </ul>`;\n      }\n\n      // feedback\n      const feedbackCard = document.getElementById("feedback-card");\n      const feedbackEl   = document.getElementById("feedback");\n      if (data.feedback) {\n        feedbackEl.innerHTML = renderMarkdown(data.feedback);\n        feedbackCard.style.display = "block";\n      } else {\n        feedbackCard.style.display = "none";\n      }\n\n      results.classList.add("show");\n      results.scrollIntoView({ behavior: "smooth", block: "start" });\n\n    } catch (err) {\n      showError("Request failed: " + ((err && err.message) ? err.message : err) + " (it may have timed out).");\n      console.error(err);\n    }\n  });\n</script>\n</body>\n</html>\n'
